#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=105,M=2005;
const ll mod=998244353;
ll n,m,a[N][M],s[N],dp[2][M],sum[N][N],jian;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cin>>a[i][j];

			s[i]=(s[i]+a[i][j])%mod;
		}
	}
	for(int i=1;i<=m;i++) 
	{
		memset(dp,0,sizeof(dp));
		dp[0][n+1]=1;
		for(int j=1;j<=n;j++)
		{
			for(int k=1;k<=1+2*n;k++)
			{
				dp[j%2][k]=(dp[(j-1)%2][k]+a[j][i]*dp[(j-1)%2][k-1]%mod+(s[j]+mod-a[j][i])%mod*dp[(j-1)%2][k+1]%mod)%mod;
			}
		}
		for(int j=n+2;j<=1+2*n;j++) jian=(jian+dp[n%2][j])%mod;
	}
	// cout<<jian<<"\n";
	sum[0][0]=1;
	for(int i=1;i<=n;i++)
	{
		sum[i][0]=sum[i-1][0];
		for(int j=1;j<=n;j++)
		{
			sum[i][j]=(sum[i-1][j]+s[i]*sum[i-1][j-1])%mod;
            // cout<<i<<" "<<j<<" "<<sum[i][j]<<"\n";
		}
	}
	ll summ=-1;
	for(int i=0;i<=n;i++)
	{
		summ=(sum[n][i]+summ)%mod;
	}
    // summ--;
	// cout<<summ<<'\n';
	// cout<<summ+mod-jian;
	cout<<(summ-jian+mod)%mod;
	return 0;
}
